+    FILE *temp = tmpfile();
+    assert(temp != NULL);
+    JS_ComputeMemoryUsage(rt, &stats);
+    JS_DumpMemoryUsage(temp, &stats, rt);
+    // JS_DumpMemoryUsage(stdout, &stats, rt);
+    fclose(temp);
+
+    JS_FreeContext(ctx);
+    JS_FreeRuntime(rt);
+}
