+        m = JS_NewCModule(ctx, module_name, js_module_dummy_init);
+    } else if (js__has_suffix(module_name, ".so")) {
+        JS_ThrowReferenceError(ctx, "%s: dynamically linking to shared libraries not supported",
+        module_name);
+        return NULL;
+    } else {
+        size_t buf_len;
+        uint8_t *buf;
+        JSValue func_val;
+        char cname[1000];
